const http = require('http');

function dockerApi(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      socketPath: '/var/run/docker.sock',
      path,
      method,
      headers: { 'Content-Type': 'application/json' },
    };
    const req = http.request(options, res => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: JSON.parse(data) });
        } catch {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

function dockerExecRaw(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      socketPath: '/var/run/docker.sock',
      path,
      method,
      headers: { 'Content-Type': 'application/json' },
    };
    const req = http.request(options, res => {
      const chunks = [];
      res.on('data', chunk => chunks.push(chunk));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        let output = '';
        let offset = 0;
        while (offset < buf.length) {
          if (offset + 8 > buf.length) break;
          const size = buf.readUInt32BE(offset + 4);
          if (offset + 8 + size > buf.length) {
            output += buf.slice(offset + 8).toString('utf8');
            break;
          }
          output += buf.slice(offset + 8, offset + 8 + size).toString('utf8');
          offset += 8 + size;
        }
        resolve(output);
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const execCreate = await dockerApi('POST', '/containers/promptfoo/exec', {
  AttachStdout: true,
  AttachStderr: true,
  Cmd: ['sh', '-c', 'cd /app && promptfoo eval --no-cache -c promptfooconfig.yaml 2>&1']
});

if (execCreate.status !== 201) {
  return [{ json: { error: 'Failed to create exec', detail: JSON.stringify(execCreate.body) } }];
}

const execId = execCreate.body.Id;
const output = await dockerExecRaw('POST', '/exec/' + execId + '/start', {
  Detach: false,
  Tty: false
});

const inspect = await dockerApi('GET', '/exec/' + execId + '/json');

const resultsMatch = output.match(/(\d+) passed.*?(\d+) failed.*?(\d+) errors.*?\(([\d.]+)%\)/);

let passed = 0, failed = 0, errors = 0, score = 0;
if (resultsMatch) {
  passed = parseInt(resultsMatch[1]);
  failed = parseInt(resultsMatch[2]);
  errors = parseInt(resultsMatch[3]);
  score = parseFloat(resultsMatch[4]);
}

return [{
  json: {
    timestamp: new Date().toISOString(),
    passed,
    failed,
    errors,
    score,
    total: passed + failed + errors,
    exitCode: inspect.body?.ExitCode ?? -1,
    rawOutput: output.substring(output.length - 500)
  }
}];

const data = $input.first().json;
const alertMsg = `Atlas Operator Eval Regression

Score: ${data.score}% (threshold: 90%)
Passed: ${data.passed}/${data.total}
Failed: ${data.failed}
Errors: ${data.errors}
Timestamp: ${data.timestamp}

Check Promptfoo UI at http://localhost:3005 for details.`;

return [{ json: { ...data, alert: true, alertMessage: alertMsg } }];
